[
    {
        "role": "paragraph",
        "segment": "Microservices architecture differs from service-oriented architecture (SOA) primarily in the granularity and independence of services.",
        "citations": []
    },
    {
        "role": "paragraph",
        "segment": "In SOA, services are typically larger, more coarse-grained, and often share resources such as databases, whereas microservices are smaller, fine-grained, and independently deployable units that encapsulate their own data and functionality.",
        "citations": []
    },
    {
        "role": "paragraph",
        "segment": "When migrating from a monolithic architecture to microservices, there are several tradeoffs to consider:",
        "citations": []
